// mm/src/steps/previewStage.js
import React, { useMemo, useState } from 'react';
import { useWorkflow } from '../store/workflowContext';

// Fallback text if we don't yet have previewText from the upload
const FALLBACK_TEXT = [
  'In the quiet town of Millbrook, where autumn leaves danced through cobblestone streets and the scent of fresh bread wafted from corner bakeries, something remarkable was about to unfold.',
  'Margaret closed her weathered journal, its pages filled with decades of dreams and observations. Today marked the beginning of a new chapter—not just in her writing, but in her life.',
  '"Every story begins with a single word," she whispered to herself, pen hovering over a fresh page. "And every word carries the weight of possibility."',
].join(' ');

// Split a long string into page-sized chunks (simple char-based chunking)
function chunkTextToPages(text, charsPerPage = 950) {
  const cleaned = (text || '').replace(/\s+/g, ' ').trim();
  if (!cleaned) return [];

  const pages = [];
  let start = 0;

  while (start < cleaned.length) {
    let end = start + charsPerPage;
    if (end >= cleaned.length) {
      pages.push(cleaned.slice(start).trim());
      break;
    }
    // Try not to cut in the middle of a word
    let lastSpace = cleaned.lastIndexOf(' ', end);
    if (lastSpace <= start + 200) lastSpace = end; // avoid tiny pages
    pages.push(cleaned.slice(start, lastSpace).trim());
    start = lastSpace + 1;
  }

  return pages;
}

function Page({ page, align = 'left' }) {
  const base =
    'w-1/2 h-[360px] bg-slate-50 border border-slate-200 flex flex-col px-10 py-10';

  if (!page) {
    return <div className={`${base} rounded-lg`} />;
  }

  if (page.type === 'title') {
    return (
      <div
        className={`${base} rounded-lg`}
        style={{ justifyContent: 'center', alignItems: 'center' }}
      >
        <div className="text-center">
          <div className="text-3xl font-serif font-semibold mb-3">
            {page.title}
          </div>
          <div className="text-xs uppercase tracking-wide text-slate-400">
            by
          </div>
          <div className="text-lg text-slate-600 mt-1">{page.author}</div>
        </div>
      </div>
    );
  }

  return (
    <div
      className={`${base} rounded-lg ${
        align === 'right'
          ? 'border-l-0 rounded-l-none'
          : 'border-r-0 rounded-r-none'
      }`}
    >
      <div className="text-xs uppercase tracking-wide text-slate-400 mb-2">
        Chapter Preview
      </div>
      <div className="text-[15px] leading-relaxed text-slate-800">
        {page.text}
      </div>
    </div>
  );
}

function Spread({ leftPage, rightPage }) {
  return (
    <div className="relative max-w-3xl mx-auto mt-6 mb-6 flex shadow-[0_20px_45px_rgba(15,23,42,0.15)] rounded-lg overflow-hidden bg-white">
      <Page page={leftPage} align="left" />
      <Page page={rightPage} align="right" />
      {/* book spine */}
      <div className="absolute inset-y-4 left-1/2 w-px bg-slate-200" />
    </div>
  );
}

export default function PreviewStep() {
  const { bookDetails = {}, design = {}, previewText } = useWorkflow();

  const title = bookDetails.title || 'Your Book Title';
  const author = bookDetails.author || 'Author Name';

  // Build virtual pages: 2 x title pages, then content pages from uploaded file
  const pages = useMemo(() => {
    const source =
      previewText && previewText.trim() ? previewText : FALLBACK_TEXT;

    const contentPages = chunkTextToPages(source, 950).map((t) => ({
      type: 'content',
      text: t,
    }));

    const titlePages = [
      { type: 'title', title, author },
      { type: 'title', title, author },
    ];

    return [...titlePages, ...contentPages];
  }, [previewText, title, author]);

  const [pageIndex, setPageIndex] = useState(0);

  const totalPages = pages.length || 1;
  const leftPage = pages[pageIndex] || null;
  const rightPage = pages[pageIndex + 1] || null;

  const canPrev = pageIndex > 0;
  const canNext = pageIndex + 2 < totalPages;

  const handlePrev = () => {
    if (!canPrev) return;
    setPageIndex((prev) => Math.max(0, prev - 2));
  };

  const handleNext = () => {
    if (!canNext) return;
    setPageIndex((prev) => Math.min(totalPages - 2, prev + 2));
  };

  const shownPages = Math.min(pageIndex + 2, totalPages);
  const progress = Math.round((shownPages / totalPages) * 100);

  // Design choices from previous step
  const typography = (design.typography || 'hybrid').toLowerCase();
  const layout = (design.layout || 'standard').toLowerCase();
  const trim = (design.trim || '5.5x8.5').replace('x', '×');

  return (
    <div className="grid grid-cols-1 lg:grid-cols-[2fr_minmax(260px,1fr)] gap-8">
      {/* LEFT: book preview */}
      <div>
        <div className="bg-white rounded-2xl shadow-sm p-6">
          <div className="text-sm text-slate-500 mb-1">
            Live Preview – {trim}" Format
          </div>

          <Spread leftPage={leftPage} rightPage={rightPage} />

          {/* Page controls */}
          <div className="flex items-center justify-between mt-2 mb-4">
            <button
              onClick={handlePrev}
              disabled={!canPrev}
              className={`inline-flex items-center text-sm px-3 py-1.5 rounded-md border ${
                canPrev
                  ? 'border-slate-200 text-slate-700 hover:bg-slate-50'
                  : 'border-slate-100 text-slate-300 cursor-default'
              }`}
            >
              ‹ Previous
            </button>

            <div className="flex items-center gap-1">
              {[0, 1, 2].map((i) => {
                const spreadIndex = pageIndex / 2;
                return (
                  <span
                    key={i}
                    className={`w-1.5 h-1.5 rounded-full ${
                      Math.round(spreadIndex) === i
                        ? 'bg-slate-900'
                        : 'bg-slate-300'
                    }`}
                  />
                );
              })}
            </div>

            <button
              onClick={handleNext}
              disabled={!canNext}
              className={`inline-flex items-center text-sm px-3 py-1.5 rounded-md border ${
                canNext
                  ? 'border-slate-200 text-slate-700 hover:bg-slate-50'
                  : 'border-slate-100 text-slate-300 cursor-default'
              }`}
            >
              Next ›
            </button>
          </div>

          {/* Progress bar */}
          <div className="mt-2">
            <div className="w-full h-1.5 bg-slate-100 rounded-full overflow-hidden mb-1">
              <div
                className="h-1.5 bg-blue-600 transition-all"
                style={{ width: `${progress}%` }}
              />
            </div>
            <div className="text-[11px] text-slate-500 text-right">
              {progress}% of pages previewed
            </div>
          </div>
        </div>
      </div>

      {/* RIGHT: "Your Design" sidebar like your screenshot */}
      <div>
        <div className="bg-white rounded-2xl shadow-sm p-6 h-full flex flex-col">
          <h3 className="text-lg font-semibold mb-4">Your Design</h3>
          <dl className="space-y-3 text-sm">
            <div className="flex justify-between">
              <dt className="text-slate-500">Typography</dt>
              <dd className="font-medium capitalize">{typography}</dd>
            </div>
            <div className="flex justify-between">
              <dt className="text-slate-500">Layout</dt>
              <dd className="font-medium capitalize">{layout}</dd>
            </div>
            <div className="flex justify-between">
              <dt className="text-slate-500">Trim</dt>
              <dd className="font-medium">{trim}"</dd>
            </div>
          </dl>

          <p className="mt-6 text-xs text-slate-500">
            Tip: you can go back to the Design step to tweak any option.
          </p>
        </div>
      </div>
    </div>
  );
}
